import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";

interface TS {
  prefix: string;
  group: string;
  sub: string;
  difficulty: D;
  items: Array<[string, string, string, string]>;
}

function gen(sets: TS[]): ScenarioQuestion[] {
  const r: ScenarioQuestion[] = [];
  for (const s of sets) {
    for (let i = 0; i < s.items.length; i++) {
      const [sc, qu, a, f] = s.items[i];
      r.push({ id: `${s.prefix}-${i+1}`, formatType: "scenario", categoryGroup: s.group, subcategory: s.sub, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: s.difficulty });
    }
  }
  return r;
}

const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

const sets: TS[] = [
  { prefix:"sq-et2-ipb1", group:ip, sub:"behavioral", difficulty:"beginner", items:[
    ["You helped a fellow student during a difficult clinical day.","How do you support teammates under stress?","I noticed my classmate was overwhelmed after a difficult patient interaction. I offered to help with their documentation while they took a brief break to regroup. Afterward, I listened to their concerns without judgment. Supporting colleagues during difficult moments builds team resilience and models the collaborative culture I want to create.","Practical peer support during challenging moments."],
    ["You managed a high-stress situation calmly.","How do you maintain composure under pressure?","During a simulation where the patient was rapidly deteriorating, I used focused breathing, prioritized my actions using the ABCs, and communicated clearly with my team. My instructor noted that my calm demeanor helped the entire team perform better. I have learned that composure is contagious—and so is panic.","Composure as a team stabilizer."],
    ["You are asked about your commitment to the nursing profession.","Why did you choose nursing over other healthcare careers?","I chose nursing because it combines scientific knowledge with human connection in a way no other profession does. Nurses are with patients 24/7, advocating, educating, and caring. I wanted a career where I could make a tangible difference every single day, and nursing provides that opportunity consistently.","Authentic professional choice rationale."],
    ["You went above normal expectations during a clinical rotation.","How do you demonstrate initiative in clinical settings?","I noticed that patients on our unit did not have a clear understanding of their daily goals. I created simple goal cards that nurses could update each morning. The patients reported feeling more involved in their care, and the unit adopted the cards permanently. Taking initiative to improve small things creates meaningful change.","Initiative-driven patient engagement improvement."],
    ["You adapted to working with different personality types.","How do you work with people whose personality differs from yours?","I recognize that diverse perspectives strengthen teams. I adapt my communication style—being more direct with task-oriented colleagues and more supportive with relationship-oriented ones. I focus on shared goals rather than personality differences. I have learned that the best teams are not groups of similar people but groups of different people who respect each other.","Adaptive communication with diverse personalities."],
    ["You are asked about your greatest weakness.","What is your biggest professional weakness?","I tend to be overly self-critical, which sometimes prevents me from recognizing my progress. I have been working on this by keeping a clinical confidence journal where I document daily wins, no matter how small. I have also learned to accept feedback objectively rather than taking it as a personal failure. This awareness helps me maintain perspective.","Genuine weakness with active improvement strategy."],
    ["You participated in community health outreach.","How has community involvement shaped your nursing perspective?","Volunteering at health fairs in underserved neighborhoods showed me that healthcare disparities start long before patients reach the hospital. Social determinants—housing, food access, education—directly impact health outcomes. This experience motivates me to assess the whole patient, including their social context, not just their medical diagnosis.","Community experience shaping holistic assessment."],
    ["You managed competing academic and personal priorities.","How do you balance competing demands?","I use the Eisenhower matrix—categorizing tasks as urgent/important, important/not urgent, urgent/not important, and neither. This helps me focus energy where it matters most. During nursing school, this system helped me maintain a 3.8 GPA while working part-time and volunteering. Systematic prioritization prevents reactive scrambling.","Framework-based life management."],
  ]},
  { prefix:"sq-et2-ipb2", group:ip, sub:"behavioral", difficulty:"intermediate", items:[
    ["You challenged an evidence gap in clinical practice.","How do you apply evidence-based practice?","I noticed our unit was using a wound care product that newer evidence suggested was less effective than alternatives. I researched the current literature, presented findings to the wound care committee, and proposed a trial of the evidence-based alternative. The trial showed improved healing times, and the unit changed its practice. Questioning 'we have always done it this way' drives improvement.","Evidence-based practice change leadership."],
    ["You navigated a complex ethical situation in clinical.","How do you approach ethical complexity?","I cared for a patient whose family and healthcare team disagreed about treatment goals. I advocated for an ethics committee consultation, facilitated a family meeting, and ensured the patient's documented wishes were central to the discussion. The experience taught me that ethical situations rarely have simple answers, but structured processes help navigate complexity.","Ethics committee utilization for complex situations."],
    ["You recovered from a professional setback.","How do you handle professional adversity?","I failed a clinical competency check on my first attempt, which was devastating. Instead of giving up, I analyzed my mistakes, practiced extensively in the simulation lab, and sought additional mentoring. I passed on my second attempt with confidence. The setback taught me that failure is feedback, not a final verdict.","Resilience through structured recovery from setbacks."],
    ["You collaborated across disciplines to improve patient outcomes.","Describe effective interdisciplinary collaboration.","I identified that diabetic patients on our unit had inconsistent education across disciplines. I proposed a standardized diabetes education pathway involving nursing, dietary, pharmacy, and social work. Each discipline contributed their expertise to create a comprehensive, non-redundant education plan. Patient knowledge scores on discharge improved by 40%.","Interdisciplinary collaboration for standardized education."],
    ["You demonstrated cultural humility in patient care.","How do you practice cultural humility?","I cared for a Muslim patient during Ramadan who was fasting despite being ill. Rather than insisting they eat, I consulted with their imam about health exemptions in Islam and worked with the medical team to adjust medication timing around fasting hours. I learned that cultural humility means learning from the patient, not assuming I know best.","Patient-as-teacher in cultural care."],
    ["You handled a situation where you had to say something unpopular.","How do you communicate difficult messages?","I identified a workflow that the entire unit loved but that was creating documentation gaps. I presented data showing the safety concern at a staff meeting, acknowledging the workflow's benefits while explaining the risk. The team initially resisted, but the data was compelling. Speaking up with evidence, even when unpopular, is essential for safety.","Data-backed unpopular truth delivery."],
    ["You identified a personal bias that affected your care.","How do you address your own biases?","I recognized I was spending less time educating patients with substance use disorders because of unconscious assumptions about their engagement. When I noticed this pattern, I deliberately adjusted my approach—providing the same thorough education regardless of diagnosis. Self-awareness about bias is the first step to equitable care.","Self-identified bias correction."],
    ["You influenced positive change in your work environment.","How do you create positive change?","I proposed a peer recognition program on our unit where nurses could nominate colleagues for exceptional care. I created simple nomination cards and a monthly celebration. Staff morale improved measurably, and the program was adopted by other units. Small positive changes can transform workplace culture when championed consistently.","Positive culture change through recognition programs."],
  ]},
  { prefix:"sq-et2-ipc1", group:ip, sub:"clinical_judgment", difficulty:"beginner", items:[
    ["A patient complains of burning during urination.","What does dysuria suggest?","Burning during urination suggests a urinary tract infection. I would obtain a urine sample for urinalysis and culture, assess for other UTI symptoms (frequency, urgency, suprapubic pain, fever), encourage increased fluid intake, and notify the provider. UTIs are common hospital-acquired infections, especially in catheterized patients.","UTI symptom recognition and assessment."],
    ["A patient has bilateral pitting edema in their lower extremities.","What causes bilateral lower extremity edema?","Bilateral pitting edema can indicate heart failure, liver disease, renal failure, medication side effects, or venous insufficiency. I would assess for other symptoms of the underlying cause, check daily weights, measure edema severity with the pitting scale, review medications, and elevate the legs. I would notify the provider for evaluation.","Bilateral edema differential with assessment."],
    ["A patient reports difficulty swallowing their medications.","How would you address medication swallowing difficulties?","I would assess the specific difficulty: pill size, number of pills, dry mouth, or physiological dysphagia. I would request alternative formulations (liquid, crushable, smaller pills) from pharmacy. I would teach proper pill-taking technique: sitting upright, taking pills with adequate water, and tilting the chin appropriately. I would never crush medications without verifying crushability.","Medication swallowing assessment and adaptation."],
    ["A patient has a temperature of 101.5°F.","How would you assess and manage a fever?","I would check for other infection signs, review recent procedures or surgeries, obtain blood cultures if ordered, administer antipyretics as prescribed, ensure adequate hydration, and apply cooling measures. I would monitor the fever trend and notify the provider if it is new or worsening. Fever is often the first sign of infection and warrants investigation.","Systematic fever assessment and management."],
    ["A patient reports sudden onset of chest heaviness after eating.","How would you differentiate cardiac from GI chest symptoms?","I would perform a comprehensive assessment: obtain vital signs, a 12-lead ECG, and oxygen saturation. I would characterize the pain—location, radiation, quality, aggravating and relieving factors. Cardiac pain is typically pressure-like, radiating to the left arm or jaw, with diaphoresis. GI pain may be related to meals and relieved by antacids. Until cardiac cause is ruled out, I would treat it as cardiac.","Conservative cardiac-first chest pain assessment."],
    ["A patient on oxygen therapy has dry nasal passages.","How would you manage oxygen therapy side effects?","I would ensure the oxygen is humidified if delivered at rates above 4 L/min. I would apply water-based nasal lubricant, ensure adequate oral hydration, and check the nasal cannula for proper fit. I would assess skin behind the ears for breakdown from the tubing. These comfort measures improve patient compliance with oxygen therapy.","Oxygen therapy comfort management."],
    ["A patient reports feeling dizzy when getting out of bed.","How would you assess orthostatic hypotension?","I would measure blood pressure and heart rate in three positions: lying, sitting, and standing, with 1-3 minutes between position changes. Orthostatic hypotension is defined as a systolic drop of 20 mmHg or diastolic drop of 10 mmHg upon standing. I would assess for dehydration, review medications (antihypertensives are common causes), and implement fall precautions.","Orthostatic hypotension assessment technique."],
    ["A patient's stool is black and tarry.","What does melena indicate?","Black, tarry stools (melena) indicate upper gastrointestinal bleeding—the blood has been partially digested as it passes through the GI tract. I would assess vital signs for hemodynamic compromise, check hemoglobin, test stool for occult blood, ensure IV access, and notify the provider. Common causes include peptic ulcers, esophageal varices, and gastritis.","Melena as upper GI bleeding indicator."],
  ]},
  { prefix:"sq-et2-ipc2", group:ip, sub:"clinical_judgment", difficulty:"intermediate", items:[
    ["A patient develops jugular vein distention while sitting upright.","What does JVD indicate?","JVD while sitting upright (normally veins collapse above the sternal angle at 30-45°) indicates elevated central venous pressure. Common causes include right heart failure, cardiac tamponade, superior vena cava syndrome, or tension pneumothorax. I would assess for other related symptoms, obtain vital signs, and notify the provider for cardiac evaluation.","JVD as elevated CVP indicator."],
    ["A patient post-appendectomy develops a fever on day 3.","What are common causes of post-operative fever by timing?","Post-operative fever timing helps identify the cause—using the 'W' mnemonic: Wind (atelectasis, day 1-2), Water (UTI, day 3-5), Wound (surgical site infection, day 5-7), Walking (DVT/PE, day 5+), Wonder drugs (drug fever, any time). Day 3 fever most commonly suggests UTI. I would obtain a urinalysis, assess for other sources, and ensure adequate hydration and ambulation.","Post-operative fever differential by timing."],
    ["A patient develops paradoxical pulse.","What does pulsus paradoxus indicate?","Pulsus paradoxus is an exaggerated decrease (>10 mmHg) in systolic blood pressure during inspiration. It is associated with cardiac tamponade, severe asthma, COPD exacerbation, and constrictive pericarditis. I would assess with a manual blood pressure cuff, noting the pressure difference between the first Korotkoff sound during expiration and the first sound during inspiration.","Pulsus paradoxus assessment and significance."],
    ["A patient receiving chemotherapy has an absolute neutrophil count of 500.","What does severe neutropenia require?","An ANC of 500 (normal 2,500-7,500) indicates severe neutropenia with high infection risk. I would implement neutropenic precautions: private room, hand hygiene enforcement, no fresh flowers or plants, cooked foods only, and monitoring for any infection signs. Even a low-grade fever requires immediate blood cultures and empiric antibiotics. I would avoid rectal procedures and minimize invasive procedures.","Neutropenic precautions for immunocompromised patients."],
    ["A patient with a VP shunt develops headache, vomiting, and altered mental status.","What might these symptoms indicate about the shunt?","These symptoms suggest VP shunt malfunction—either obstruction or infection. I would perform a neurological assessment, check for signs of increased intracranial pressure (papilledema, sunset eyes), and notify the neurosurgeon immediately. I would not lower the head of bed as this can worsen ICP. CT scan and possible shunt tap may be needed for diagnosis.","VP shunt malfunction recognition."],
    ["A patient receiving blood products develops temperature increase of 1°C without other symptoms.","Is this a concerning transfusion reaction?","A temperature increase of 1°C during transfusion without other symptoms is a febrile non-hemolytic transfusion reaction—the most common type. I would slow or temporarily stop the transfusion, administer antipyretics as ordered, monitor closely for progression to more serious symptoms, and notify the provider. The transfusion can often be continued with premedication.","Febrile non-hemolytic reaction management."],
    ["A patient with a prosthetic joint develops unexplained fever and joint pain.","What complication should you suspect?","Unexplained fever with joint pain near a prosthetic joint suggests prosthetic joint infection—a serious complication that often requires surgical intervention. I would assess the joint for warmth, swelling, and erythema, obtain blood cultures and inflammatory markers, and notify the orthopedic surgeon immediately. Prosthetic joint infections can be devastating and may require joint removal.","Prosthetic joint infection recognition."],
    ["A patient on TPN develops metabolic alkalosis.","What might cause metabolic alkalosis during TPN?","TPN can cause metabolic alkalosis from excessive acetate in the formulation (acetate is metabolized to bicarbonate). I would check electrolytes, particularly chloride, and notify the provider for TPN reformulation. I would also check for other causes: NG suction, diuretics, or hypokalemia. The pharmacy team can adjust the acetate-to-chloride ratio in the TPN.","TPN formulation-related metabolic derangement."],
  ]},
  { prefix:"sq-et2-ipc3", group:ip, sub:"clinical_judgment", difficulty:"advanced", items:[
    ["A patient on CRRT develops electrolyte derangements.","How would you manage electrolyte monitoring during CRRT?","I would check electrolytes every 4-6 hours during CRRT as the continuous nature of the therapy can rapidly change electrolyte levels. I would monitor calcium, magnesium, phosphorus, and potassium closely. I would anticipate replacement needs and communicate trends to the nephrologist. I would also monitor the acid-base balance as CRRT affects bicarbonate levels.","CRRT electrolyte monitoring protocols."],
    ["A patient develops transfusion-related acute lung injury.","How would you manage TRALI?","TRALI is a serious lung injury occurring within 6 hours of transfusion, presenting with acute respiratory distress and bilateral pulmonary infiltrates. I would stop the transfusion immediately, provide aggressive respiratory support (oxygen, possibly ventilatory support), notify the blood bank with the implicated unit, and avoid further blood products from the same donor. Unlike other fluid overload, diuretics are not helpful in TRALI.","TRALI management distinct from fluid overload."],
    ["A patient with an ICP monitor has a reading of 25 mmHg.","How would you manage elevated intracranial pressure?","Normal ICP is 5-15 mmHg. An ICP of 25 requires immediate intervention. I would elevate the head of bed to 30 degrees, ensure the head is midline, manage fever aggressively, maintain adequate cerebral perfusion pressure, administer osmotic therapy (mannitol or hypertonic saline) as ordered, and notify the neurosurgeon. I would avoid activities that increase ICP: suctioning, Valsalva, clustering of care.","ICP management with evidence-based interventions."],
    ["A trauma patient develops the lethal triad: hypothermia, acidosis, and coagulopathy.","How would you manage the trauma triad of death?","The lethal triad creates a vicious cycle: hypothermia causes coagulopathy, coagulopathy causes hemorrhage, hemorrhage causes acidosis and hypothermia. I would implement aggressive warming measures, pursue damage control surgery, administer blood products using massive transfusion protocol, and correct acidosis. Breaking the cycle requires simultaneous treatment of all three components.","Trauma lethal triad management."],
    ["A patient on high-dose vasopressors develops peripheral ischemia.","How would you manage vasopressor-induced peripheral ischemia?","I would assess extremity perfusion (color, temperature, pulses, capillary refill), notify the provider, and anticipate possible reduction of vasopressor dose if hemodynamics allow. I would assess for need for peripheral vasodilator agents. I would elevate extremities, maintain warmth, and monitor for progression. Central vasopressor administration reduces peripheral ischemia risk.","Vasopressor complication management."],
    ["A patient with a ventricular assist device develops pump malfunction alarms.","What would you do for a VAD alarm?","I would assess the patient immediately—check consciousness, vital signs, and perfusion. I would check the VAD controller for specific alarm codes and follow the device-specific troubleshooting algorithm. I would ensure backup batteries are available. I would not disconnect the VAD. I would notify the VAD coordinator and cardiothoracic surgeon. For pulseless patients with VAD failure, CPR technique may need modification.","VAD malfunction troubleshooting."],
    ["A patient develops refeeding syndrome after NPO status.","How would you manage refeeding syndrome?","Refeeding syndrome occurs when nutrition is restarted after prolonged starvation, causing dangerous electrolyte shifts. I would monitor phosphorus, magnesium, potassium, and calcium closely (every 6-12 hours initially), start nutrition slowly, supplement electrolytes aggressively, and watch for cardiac arrhythmias. Thiamine should be given before refeeding. The 'start low, go slow' principle applies to caloric intake.","Refeeding syndrome prevention and management."],
    ["A patient with an organ transplant develops cytomegalovirus reactivation.","How would you manage CMV reactivation in a transplant patient?","CMV reactivation in immunosuppressed transplant patients can cause end-organ disease. I would ensure ganciclovir or valganciclovir therapy is initiated, monitor CMV viral load, assess for organ involvement (GI, retinal, pulmonary), and coordinate with the transplant team about immunosuppression adjustments. I would implement contact precautions and monitor for drug side effects, particularly neutropenia from ganciclovir.","Post-transplant CMV management."],
  ]},
  { prefix:"sq-et2-ws1", group:ws, sub:"prioritization", difficulty:"beginner", items:[
    ["You need to hang an antibiotic and take a set of vital signs.","Which task comes first?","If the antibiotic has a specific timing requirement (like Q8H with strict timing), it takes priority. Otherwise, I would assess the clinical context—vital signs on a potentially unstable patient take priority. For a stable patient with routine vitals, I would hang the antibiotic first. Clinical judgment about context drives prioritization.","Context-dependent clinical prioritization."],
    ["A patient wants their lunch tray and another needs a dressing change.","How would you prioritize nutrition versus wound care?","The dressing change takes clinical priority—wound exposure increases infection risk. I would ask support staff to deliver the lunch tray while I perform the dressing change. Both needs are important, but clinical needs supersede comfort needs. I would explain the brief delay to the hungry patient.","Clinical tasks before comfort tasks."],
    ["Two patients need pain medication at the same time.","How would you prioritize two simultaneous pain medication requests?","I would assess which patient has higher pain severity, more acute condition, or has been waiting longer. I would administer to the higher-priority patient first, then immediately get the second patient's medication. If both are equally urgent, I would ask a colleague to help administer one while I do the other.","Pain severity-based prioritization."],
    ["A patient needs a scheduled bath and another has a new order to implement.","Which takes priority—hygiene or new orders?","New orders take priority as they may represent clinical decisions based on changing patient conditions. I would review and implement the new orders first, especially if they are time-sensitive (medications, tests, consultations). The bath can be safely rescheduled. I would delegate the bath to a CNA if possible.","New clinical orders before routine care."],
    ["You have three call lights ringing simultaneously.","How would you manage three simultaneous call lights?","I would quickly assess what I know about each patient: fall risk, acuity level, and recent condition changes. I would respond to the highest-risk patient first, delegate another to support staff, and acknowledge the third by intercom if possible. Systematic triage of call lights prevents responding based on proximity alone.","Risk-based call light triage."],
    ["A patient needs discharge education and another needs hourly rounding.","How would you manage education and rounding?","I would perform the hourly round first as it is a safety check. Then I would provide discharge education, which requires more focused time. I would communicate with the discharging patient: 'I will be back in 10 minutes to go over your discharge instructions.' Brief safety checks should not be skipped for longer tasks.","Safety rounding before extended education."],
    ["You need to prepare for a patient transfer and complete your charting.","Which is more time-sensitive?","Patient transfer preparation takes priority as another unit or facility is waiting and the patient's care continuity depends on timely transfer. I would prepare the transfer documentation first, complete the transfer, and then finish my remaining charting. Transfer delays can affect patient care at the receiving end.","Transfer preparation before routine documentation."],
    ["A patient requests ice chips and another has a blood sugar due.","Which task comes first?","Blood glucose monitoring is a clinical assessment with specific timing, especially for insulin-dependent patients. I would check the blood sugar first and then bring ice chips. Clinical monitoring tasks take priority over comfort requests. I would acknowledge the ice chip request and provide a timeline.","Clinical monitoring before comfort provision."],
  ]},
  { prefix:"sq-et2-ws2", group:ws, sub:"patient_safety", difficulty:"beginner", items:[
    ["A patient's IV site is red and swollen.","How would you assess and manage a potential IV infiltration?","I would stop the infusion, disconnect the IV, assess the site for phlebitis signs (red, warm, tender, cord-like vein), measure the area of redness, apply a warm compress for phlebitis or cold compress for infiltration, notify the provider, and establish new IV access at a different site. I would document the findings and complete an incident report if medication infiltrated.","IV site complication assessment and management."],
    ["A patient's call light is not working.","How would you ensure patient safety with a broken call light?","I would provide an alternative way to call for help—a hand bell, their phone, or leave the door open with instructions to call out. I would round more frequently on this patient. I would immediately report the broken call light for repair. A functional call light is a patient safety requirement, not optional equipment.","Alternative patient communication during equipment failure."],
    ["A patient is not wearing their non-slip socks.","How would you address fall prevention compliance?","I would provide non-slip socks and explain their purpose: 'These special socks help prevent you from slipping on the floor. Falls in the hospital can cause serious injuries. Would you like me to help you put them on?' I would assess why they removed them—discomfort, temperature, or forgetfulness—and address the underlying issue.","Patient education for fall prevention compliance."],
    ["A patient's bed alarm keeps going off due to restlessness.","How would you manage frequent false bed alarms?","I would assess why the patient is restless—pain, anxiety, need for toileting, or delirium. I would address the underlying cause rather than just resetting the alarm. I would adjust the alarm sensitivity if appropriate. I would never disable the alarm for a high-risk patient. Alarm fatigue from false alarms is dangerous, but addressing root causes is the solution.","Root cause approach to alarm management."],
    ["A patient on fall precautions needs to use the bathroom.","How would you safely assist a high-risk patient to the bathroom?","I would clear the path of obstacles, lower the bed, ensure non-slip footwear is on, assist them to standing slowly (assessing for orthostatic symptoms), walk with them using a gait belt if appropriate, stay close by during bathroom use, and assist them back to bed safely. I would document the activity and ambulation tolerance.","Safe toileting assistance for high-risk patients."],
    ["A patient has multiple IV lines and is getting tangled in tubing.","How would you manage multiple IV line organization?","I would label each line clearly at the connection point and at the pump, trace each line from source to patient, use a line organizer or color-coded labels, secure tubing to prevent tangling, and educate the patient about being careful when moving. Line management prevents medication errors and reduces trip/pull risks.","Multi-line IV organization for safety."],
    ["A patient is reaching for items that are out of their safe reach.","How would you prevent reaching-related falls?","I would position all essential items—call light, water, phone, tissues, remote—within the patient's safe reach. I would use a bedside table at appropriate height. I would educate the patient to call for help rather than reaching or stretching. Reaching for items is one of the most common precipitating events for patient falls.","Environmental arrangement for fall prevention."],
    ["A patient's wrist identification band is too tight.","How would you manage an uncomfortable identification band?","I would check for skin integrity under the band, assess for adequate circulation (capillary refill, sensation), and replace the band with appropriate sizing. A properly fitting band allows one finger to slide underneath. I would never remove the band without immediately replacing it—patient identification must be maintained at all times.","Identification band comfort and safety management."],
  ]},
  { prefix:"sq-et2-ws3", group:ws, sub:"medication_error", difficulty:"beginner", items:[
    ["You notice a medication label that is partially torn.","How would you handle a damaged medication label?","I would not administer any medication with an unreadable or damaged label. I would return it to pharmacy and request a properly labeled replacement. I would never guess what a medication is based on appearance alone. Proper labeling is a fundamental safety requirement.","Label verification as safety baseline."],
    ["A patient asks what a specific medication is for.","How would you provide medication education?","I would explain the medication name, purpose, expected effects, common side effects to watch for, and any special administration instructions. I would verify the patient's understanding and encourage questions. If I am unfamiliar with the medication, I would research it before administration. Patient education is a right and a safety strategy.","Patient-centered medication education."],
    ["You realize the medication you are about to give requires monitoring parameters you have not checked.","How would you handle missing pre-administration assessments?","I would hold the medication until I complete the required assessment. For example, I would not give digoxin without checking the heart rate, or an antihypertensive without checking blood pressure. I would document the assessment and proceed with administration if parameters are within acceptable range. Required pre-administration checks exist for patient safety.","Pre-administration assessment compliance."],
    ["A patient says they usually take their blood pressure medication at bedtime, not morning.","How would you handle patient-reported timing preference?","I would verify the order and check if the timing is clinically important. Many blood pressure medications can be taken at different times. I would contact the provider to request a schedule change to match the patient's home routine if clinically appropriate. Medication timing that aligns with home routine improves post-discharge compliance.","Patient-centered medication timing."],
    ["You are interrupted during medication preparation.","How would you manage an interruption during medication preparation?","I would not administer the medication I was preparing—I would start over to ensure accuracy. Interruptions during medication preparation are a leading cause of medication errors. I would address the interruption, then return to the preparation from the beginning. I would advocate for interruption-free zones during medication preparation.","Interruption management during high-risk tasks."],
    ["A medication comes in a different packaging than you are used to seeing.","How would you verify a medication in unfamiliar packaging?","I would verify the medication name, dose, and NDC number on the packaging. I would use barcode scanning to confirm identity. I would contact pharmacy if I have any doubts. Manufacturer packaging changes are common, and verifying beyond visual recognition prevents errors. I would not rely on appearance alone.","Medication verification beyond visual recognition."],
    ["A patient is prescribed a medication they say they have already taken today.","How would you address a possible duplicate dose?","I would hold the medication and verify: check the MAR for previous administration, ask the patient specifically when and where they took it, and contact the previous administering nurse if applicable. I would not give the dose until the situation is clarified. Duplicate dosing is a common error during care transitions.","Duplicate dose prevention through verification."],
    ["You accidentally draw up slightly more medication than needed.","How would you handle excess drawn medication?","I would waste the excess amount with a witness, documenting the waste properly. I would administer only the ordered dose. For controlled substances, the witnessed waste is especially important. I would not round up or administer the extra amount. Precise dosing is essential for medication safety.","Proper medication waste procedures."],
  ]},
  { prefix:"sq-et2-ct1", group:ct, sub:"first_shift", difficulty:"beginner", items:[
    ["You cannot find a piece of equipment you need urgently.","How would you handle missing equipment?","I would ask the nearest colleague, check the supply room, call the charge nurse, or check if another unit has the equipment. I would not delay critical patient care because of missing equipment—improvise safely if possible while the correct equipment is located. After the situation, I would report the equipment shortage to prevent recurrence.","Resourcefulness during equipment shortages."],
    ["Your first IV insertion attempt is unsuccessful.","How would you handle a failed first IV attempt?","I would remain calm, apologize to the patient, assess what went wrong, and try a second attempt at a different site if appropriate. Most facilities allow 2 attempts before requesting another nurse. I would not let embarrassment prevent me from trying again. I would ask for help from an experienced nurse or the IV team if available.","Professional recovery from procedural failure."],
    ["You are nervous about performing your first medication administration independently.","How would you manage first-time medication administration anxiety?","I would follow the five rights methodically: right patient, right drug, right dose, right route, right time. I would verify each step and use barcode scanning. I would review each medication's purpose and side effects. I would take my time—accuracy is more important than speed. Having a systematic process reduces the risk of anxiety-driven errors.","Systematic approach overcoming anxiety."],
    ["You receive your first critical lab result.","How would you handle your first critical lab notification?","I would verify the result, assess the patient, and notify the provider using SBAR with the critical value and my assessment findings. I would repeat the notification until I receive an acknowledgment and verbal order. I would document the critical value, the time I was notified, and the time and content of provider notification. I would implement any orders promptly.","Critical value notification protocol."],
    ["Your patient has a visitor who is asking clinical questions.","How would you manage visitor questions about patient care?","I would verify with the patient that they consent to sharing information with the visitor. If authorized, I would answer questions within my scope using patient-friendly language. If the questions are beyond my scope, I would direct them to the physician. I would never share information without patient authorization, regardless of the visitor's relationship.","Privacy-conscious visitor communication."],
    ["You are overwhelmed by the number of policies and protocols.","How would you manage information overload about policies?","I would focus first on the most critical policies—medication administration, emergency procedures, and safety protocols. I would save policy reference locations on my phone or a quick-reference card. I would not try to memorize everything—knowing where to find information is as important as knowing it. I would review policies relevant to my patients before each shift.","Strategic policy learning prioritization."],
    ["You need to insert a nasogastric tube for the first time.","How would you prepare for your first NG tube insertion?","I would review the procedure step by step, measure properly (nose to ear to xiphoid process), gather all supplies including backup, explain to the patient and position them appropriately, and proceed with confidence while being gentle. I would verify placement per protocol before use. If I struggle, I would ask for help rather than forcing the tube.","Thorough first-procedure preparation."],
    ["Your first patient says they want a different nurse.","How would you handle a patient requesting a different nurse?","I would not take it personally. I would ask if there is something specific I can address: 'I want to make sure you are comfortable with your care. Is there something I can do differently?' If they still prefer another nurse, I would inform the charge nurse for reassignment. Patient comfort is paramount, and this is not necessarily a reflection of my skills.","Non-defensive response to reassignment request."],
  ]},
  { prefix:"sq-et2-ct2", group:ct, sub:"new_nurse_anxiety", difficulty:"beginner", items:[
    ["You have recurring nightmares about making errors at work.","How would you manage work-related nightmares?","I would recognize this as a sign that my anxiety needs professional attention. I would utilize the Employee Assistance Program for counseling, practice stress reduction techniques before bed, and discuss my anxiety level with my preceptor. Work-related nightmares indicate my nervous system is struggling to process the stress of the new role.","Professional support for anxiety manifestations."],
    ["You feel like you cannot remember anything you learned in school.","How would you handle clinical knowledge retrieval anxiety?","I would recognize that the transition from academic to clinical knowledge retrieval takes time. I would use drug references, clinical guidelines, and assessment tools to supplement my memory. I would study one topic each day related to my patients. I would trust that my foundational knowledge is there—it just needs clinical context to become accessible.","Knowledge retrieval confidence development."],
    ["You worry about giving report to experienced nurses.","How would you overcome handoff anxiety with experienced nurses?","I would prepare my report thoroughly using a standardized format. I would practice my delivery before giving it. I would focus on the essential clinical information and not try to impress. Most experienced nurses remember being new and appreciate organized, honest reports. With each handoff, my confidence will grow.","Preparation-based handoff confidence."],
    ["You feel physically exhausted after every shift.","How would you manage physical exhaustion as a new nurse?","I would assess my self-care basics: sleep quality, nutrition, hydration, and exercise. I would invest in good shoes and compression socks. I would learn energy management techniques—taking brief breaks, sitting when possible, and managing my physical activity distribution. I would accept that the first 3-6 months are physically demanding and will improve as I build stamina and efficiency.","Physical self-care during transition period."],
    ["You feel disconnected from friends who are not in healthcare.","How would you maintain non-nursing relationships?","I would be intentional about nurturing friendships outside of nursing—scheduling regular social activities, being present during off-duty time, and finding shared interests that do not involve work. I would limit nursing talk with non-nursing friends unless they ask. Maintaining diverse relationships prevents professional isolation and promotes work-life balance.","Intentional non-nursing relationship maintenance."],
    ["You second-guess every clinical decision you make.","How would you develop clinical decision confidence?","I would track my clinical decisions and their outcomes to see that most are appropriate. I would discuss my reasoning with my preceptor for validation. I would use decision-making frameworks (if-then thinking) rather than gut feelings alone. Over time, pattern recognition develops and decision confidence follows. Every experienced nurse once second-guessed themselves.","Decision tracking for confidence building."],
    ["You feel guilty about taking sick days.","How would you manage guilt about calling in sick?","I would remind myself that working while sick endangers patients and prolongs my recovery. Nurses have a professional obligation to protect patients from communicable illness. I would follow my facility's call-in policy and not feel guilt about a reasonable human need. Presenteeism (working while sick) is a patient safety concern, not a badge of honor.","Sick leave as patient safety responsibility."],
    ["You struggle with the transition from day to night shift.","How would you adapt to night shift nursing?","I would maintain a consistent sleep schedule on work days, use blackout curtains, avoid caffeine after midnight, plan meals to avoid heavy eating at 3 AM, and stay active during the shift to prevent drowsiness. I would allow 2-3 weeks for my body to adapt. I would communicate my schedule needs to family and friends. Night shift adaptation is physiological and takes time.","Night shift adaptation strategies."],
  ]},
  { prefix:"sq-et2-pd1", group:pd, sub:"professional_boundaries", difficulty:"beginner", items:[
    ["A patient asks for your personal phone number.","How would you decline giving personal contact information?","I would say warmly: 'I appreciate the connection we have, but I need to keep my personal contact information separate from my professional role. If you have questions after discharge, your best resources are your primary care provider and the unit phone number. I wish you all the best in your recovery.'","Clear contact boundary with warm delivery."],
    ["A patient brings you a homemade gift.","How would you handle accepting a handmade gift?","I would accept it graciously if facility policy allows: 'Thank you so much—this is very thoughtful. I will treasure it.' Homemade items of nominal value are often acceptable per facility gift policies. If the gift appears expensive or inappropriate, I would politely decline while acknowledging the kind gesture. I would check my facility's specific policy.","Policy-appropriate gift acceptance."],
    ["You notice a colleague becoming too personally involved with a patient.","How would you address boundary concerns about a colleague?","I would approach them privately and with concern, not judgment: 'I have noticed you spending a lot of personal time with the patient in 305. I want to make sure you are protecting yourself professionally. Sometimes it is hard to see our own boundaries when we are close to a situation.' If the behavior does not change, I would escalate to the charge nurse.","Compassionate peer boundary intervention."],
    ["A patient asks about your religious beliefs.","How would you handle questions about personal religion?","I would redirect: 'My personal beliefs are private, but I want to make sure your spiritual needs are supported. Would you like me to arrange a visit from our chaplain, or is there a specific way I can support your spiritual practice while you are here?' I would focus on the patient's needs rather than sharing my own beliefs.","Spiritual care focus over personal disclosure."],
    ["A patient tells you they love you.","How would you respond to a patient expressing love?","I would respond with professional warmth: 'I appreciate your kind words and I care about your wellbeing too. It is my privilege to be your nurse.' I would recognize that patients sometimes express gratitude or emotional connection as love, especially during vulnerable times. I would maintain my professional role while validating their feelings.","Professional warmth in response to emotional expression."],
  ]},
  { prefix:"sq-et2-pd2", group:pd, sub:"patient_communication", difficulty:"beginner", items:[
    ["A patient does not understand medical jargon you used.","How would you simplify your medical communication?","I would apologize and rephrase: 'I am sorry for using medical terms. Let me explain that differently...' I would use analogies and plain language. I would check for understanding frequently. I would avoid jargon in future conversations with this patient. Medical communication should be accessible—if the patient does not understand, the communication has failed.","Jargon-free communication correction."],
    ["A patient does not speak during your assessment.","How would you engage a silent patient?","I would give them time and space without pressure. I would use closed-ended questions initially (yes/no), then gradually open up the conversation. I would assess for communication barriers: pain, fear, hearing deficit, language, or cognitive impairment. I would sit at their level and maintain a warm, non-threatening presence. Silence can be therapeutic when the nurse is simply present.","Patient-paced engagement strategies."],
    ["A patient asks you to explain their lab results.","How would you explain lab results to a patient?","I would explain in simple terms: 'This number measures how well your kidneys are working. The normal range is here, and your number is a bit higher, which means we need to watch it closely. The doctor will discuss what this means for your treatment.' I would not speculate about diagnoses but would provide context that helps them understand their care.","Patient-friendly lab result explanation."],
    ["A patient is hard of hearing but does not want to admit it.","How would you communicate with an unacknowledged hearing deficit?","I would adjust my communication without drawing attention to it: face them directly, speak clearly at a moderate volume, reduce background noise, and use visual cues and gestures naturally. I would not repeatedly ask 'Can you hear me?' which can be embarrassing. I would document the observation for the care team and recommend a hearing evaluation.","Discreet hearing accommodation."],
    ["A patient's child asks you a scary-sounding question about their parent's illness.","How would you address a child's questions about a parent's illness?","I would answer age-appropriately and honestly: 'Your mom is sick right now, and the doctors are helping her feel better. She is in a safe place where people take very good care of her.' I would assess the child's emotional state, offer age-appropriate comfort, and recommend the parent or family engage child life services if available.","Age-appropriate child communication."],
  ]},
  { prefix:"sq-et2-cn1", group:cn, sub:"career_advancement", difficulty:"beginner", items:[
    ["You want to learn about different nursing specialties.","How would you explore nursing career options?","I would attend specialty nursing association meetings, shadow nurses in different areas, read about specialty certifications, and attend nursing career fairs. I would talk to nurses in various specialties about their daily work, challenges, and rewards. I would consider which patient populations and clinical challenges excite me most. Career exploration is an ongoing process.","Multi-method specialty exploration."],
    ["You want to build your resume as a new nurse.","What should a new nurse include on their resume?","I would include: nursing education and GPA if strong, clinical rotation experiences with specific skills, certifications (BLS, ACLS), relevant prior healthcare experience, volunteer work, leadership roles, quality improvement projects, and professional organization memberships. I would tailor my resume to each position and include quantifiable achievements when possible.","New nurse resume building strategies."],
    ["You are unsure about your career path.","How would you navigate career uncertainty?","I would give myself permission to not have everything figured out immediately. I would explore different areas through floating, volunteering for diverse assignments, and talking to nurses at various career stages. I would identify what energizes me versus what drains me. Career paths in nursing are rarely linear—and that is one of the profession's greatest strengths.","Permission for career exploration."],
    ["You want to attend your first professional conference.","How would you get the most from a nursing conference?","I would research the conference agenda and plan which sessions to attend. I would bring business cards, attend networking events, and introduce myself to speakers. I would take notes and identify 3-5 actionable takeaways. I would share what I learned with my team afterward. I would also explore the exhibit hall for new products and resources relevant to my practice.","Conference maximization strategies."],
    ["You are considering volunteering for a committee.","What committee should a new nurse consider joining?","I would consider committees aligned with my interests and career goals: shared governance, falls prevention, patient experience, evidence-based practice, or quality improvement. I would choose a committee where I can both learn and contribute. Committee involvement demonstrates professional engagement, builds relationships, and develops leadership skills early in my career.","Strategic committee selection for development."],
  ]},
  { prefix:"sq-et2-cn2", group:cn, sub:"probation_period", difficulty:"beginner", items:[
    ["You receive conflicting feedback from your preceptor and manager.","How would you reconcile conflicting guidance?","I would seek clarification by meeting with both together if possible: 'I want to make sure I understand the expectations clearly. I have received guidance from each of you that seems to differ on this point. Can we discuss what the standard should be?' This shows professionalism and prevents being caught between conflicting expectations.","Proactive reconciliation of conflicting expectations."],
    ["You are approaching the end of your orientation and feel nervous about independence.","How would you prepare for transitioning off orientation?","I would identify specific areas where I still need support, create a plan for continued development, establish a network of resource nurses, and discuss a graduated transition with my manager. I would set realistic expectations—being off orientation does not mean I know everything. I would continue asking questions and seeking feedback for at least the first year.","Graduated independence transition planning."],
    ["You want to make a positive impression during probation.","What key behaviors establish credibility during probation?","I would focus on: consistent reliability, thoroughness in patient care, professional appearance and attitude, strong communication, willingness to learn, and team contribution. I would take feedback graciously, show initiative without overstepping, and demonstrate clinical growth over time. The single most important behavior is consistent, safe patient care.","Credibility-building behaviors during probation."],
    ["Your orientation goals change midway through probation.","How would you adapt to changing orientation expectations?","I would seek to understand why goals changed—new clinical needs, reassessment of my skills, or unit priorities. I would update my personal development plan accordingly and discuss the changes with my preceptor and educator. Flexibility during orientation shows adaptability. I would ensure the new goals are documented and progress is tracked.","Flexible adaptation to changing orientation goals."],
    ["You want to receive more feedback during probation.","How would you request more frequent feedback?","I would ask proactively: 'I value your feedback and would benefit from more regular check-ins. Could we schedule brief 10-minute discussions at the end of each shift or weekly to review my progress?' I would prepare specific questions or areas I want feedback on. Self-directed feedback-seeking is a mark of professional maturity.","Structured feedback request for professional development."],
  ]},
];

